Here's how to write modern MSTest tests for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;
    private readonly MockHttpMessageHandler _handler;
    private readonly DataFetcher _sut;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
        _handler = new MockHttpMessageHandler();
        _sut = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        _handler.ResponseContent = "hello world";

        // Act
        var result = await _sut.FetchAsync("http://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        _handler.StatusCode = System.Net.HttpStatusCode.InternalServerError;

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await _sut.FetchAsync("http://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(2000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _sut.FetchAsync("http://example.com", cts.Token));
    }

    // Minimal fake handler for testing
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public string ResponseContent { get; set; } = string.Empty;
        public System.Net.HttpStatusCode StatusCode { get; set; } = System.Net.HttpStatusCode.OK;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();

            var response = new HttpResponseMessage(StatusCode)
            {
                Content = new StringContent(ResponseContent)
            };
            return Task.FromResult(response);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| Async testing | Return `async Task` from test methods |
| Timeouts | `[Timeout(ms)]` on each test method |
| Cancellation cooperation | Pass `_testContext.CancellationToken` so timeout actually cancels the work |
| Pre-canceled token test | Create a `CancellationTokenSource`, cancel it, verify `TaskCanceledException` |
| Exception assertions | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| Sealed class | Performance + design clarity |
| Constructor init | Enables `readonly` fields, satisfies nullability |

The critical detail: **always pass `TestContext.CancellationToken`** to your async calls in tests with `[Timeout]` — this is what makes the timeout actually cancel the operation cooperatively rather than just failing after the fact.
